from fastapi import FastAPI

app = FastAPI()

@app.get("/items/{item_id}")
async def read_item(item_id: int):
    return {"item_id": item_id}

# Runs in event loop — ideal for async I/O
@app.get("/async-route")
async def async_route():
    result = await some_async_db_call()
    return result

# Runs in thread pool — safe but heavier
@app.get("/sync-route")
def sync_route():
    result = some_blocking_db_call()
    return result

# BAD: blocks the event loop
@app.get("/bad")
async def bad_endpoint():
    import time
    time.sleep(5)  # Freezes the entire event loop for 5 seconds
    return {"status": "done"}

import httpx
from fastapi import FastAPI

app = FastAPI()

# Recommended: reuse a single client across requests
http_client = httpx.AsyncClient()

@app.get("/weather/{city}")
async def get_weather(city: str):
    response = await http_client.get(
        f"https://api.example.com/weather",
        params={"city": city}
    )
    response.raise_for_status()
    return response.json()

@app.on_event("shutdown")
async def shutdown():
    await http_client.aclose()

